#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e5+5;
int n,m,id[N],low[N],tot,len,A,B,Ans;
bool cut[N];vector<int> g[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool check(int u){
    if(id[u]>id[A]&&id[u]<=id[B])return 1;
    if(id[u]<=id[A]&&id[u]>id[B])return 1;return 0;
}
void DFS(int u,int fa){
    id[u]=(++tot),low[u]=id[u];int cnt=0;
    for(int v:g[u]){
        if(v==fa)continue;
        if(id[v])low[u]=min(low[u],id[v]);
        else{
            DFS(v,u),cnt++;
            low[u]=min(low[u],low[v]);
            if(low[v]>=id[u]&&u!=A&&u!=B&&check(v))Ans=min(Ans,u);
        }
    }if(!fa&&cnt>1)cut[u]=1;return;
}
int main(){
    n=read();int x=read(),y=read();
    while(x){
        g[x].pb(y),g[y].pb(x);
        x=read(),y=read();
    }A=read(),B=read();Ans=n+1;DFS(1,0);
    if(Ans<=n)cout<<Ans<<"\n";
    else cout<<"No solution\n";
    return 0;
}
